import{_ as t,c as o,o as r,ag as a}from"./chunks/framework.DRADY2L-.js";const p=JSON.parse(`{"title":"Top 9 Frequently Asked Questions","description":"(Article in progress) The choice of drone depends on your desired flight style and conditions. Learn more. If you're too lazy to read: YouTube Video. If you'...","frontmatter":{"description":"(Article in progress) The choice of drone depends on your desired flight style and conditions. Learn more. If you're too lazy to read: YouTube Video. If you'...","gitAuthors":["mituritsyn","ikherty","Valentina Petrenko"]},"headers":[],"relativePath":"settings/FAQ.md","filePath":"en/settings/FAQ.md","lastUpdated":1774721624000}`),n={name:"settings/FAQ.md"};function i(s,e,l,h,d,u){return r(),o("div",null,[...e[0]||(e[0]=[a('<h1 id="top-9-frequently-asked-questions" tabindex="-1">Top 9 Frequently Asked Questions <a class="header-anchor" href="#top-9-frequently-asked-questions" aria-label="Permalink to &quot;Top 9 Frequently Asked Questions&quot;">​</a></h1><p>(Article in progress)</p><h2 id="hello-i-m-a-beginner-which-drone-should-i-choose" tabindex="-1">Hello, I&#39;m a beginner. Which drone should I choose? <a class="header-anchor" href="#hello-i-m-a-beginner-which-drone-should-i-choose" aria-label="Permalink to &quot;Hello, I&#39;m a beginner. Which drone should I choose?&quot;">​</a></h2><p>The choice of drone depends on your desired flight style and conditions. <a href="https://propwashservice.com/en/intro/flightstyles" target="_blank" rel="noreferrer">Learn more</a>.</p><h2 id="why-do-the-motors-rev-up-increase-rpm-when-i-lower-the-throttle" tabindex="-1">Why do the motors rev up (increase RPM) when I lower the throttle? <a class="header-anchor" href="#why-do-the-motors-rev-up-increase-rpm-when-i-lower-the-throttle" aria-label="Permalink to &quot;Why do the motors rev up (increase RPM) when I lower the throttle?&quot;">​</a></h2><p>If you&#39;re too lazy to read: <a href="https://www.youtube.com/watch?v=OBiZbcUN2Lc&amp;" target="_blank" rel="noreferrer">YouTube Video</a>.</p><p>If you&#39;re too lazy to watch: The drone is trying to work correctly even though you haven&#39;t put propellers on it. It received a command to &quot;increase motor RPM,&quot; which it interprets as &quot;increase RPM to move,&quot; and it tries to fly. But an error occurs—the motors increased RPM, but the sensor readings indicated the drone didn&#39;t move. What should the flight controller firmware do in such a case? Correct, increase RPM even more so the drone can move. But still no movement, and this continues in a loop. It&#39;s all because it won&#39;t take off without propellers. So don&#39;t torture your drone—put the props on and go fly.</p><h2 id="how-do-i-install-propellers-correctly" tabindex="-1">How do I install propellers correctly? <a class="header-anchor" href="#how-do-i-install-propellers-correctly" aria-label="Permalink to &quot;How do I install propellers correctly?&quot;">​</a></h2><p><a href="https://youtu.be/jTr0UHyp_6A" target="_blank" rel="noreferrer">Old demonstration video</a>.</p><p>Unfortunately, it doesn&#39;t mention &quot;pusher&quot; configurations, but propellers should always pull upward, so they are always oriented with the top side up, even if the motors are inverted. In the case of an airplane, &quot;upward&quot; means &quot;forward.&quot;</p><h2 id="why-is-my-drone-flipping-overturning-when-i-try-to-take-off" tabindex="-1">Why is my drone flipping (overturning) when I try to take off? <a class="header-anchor" href="#why-is-my-drone-flipping-overturning-when-i-try-to-take-off" aria-label="Permalink to &quot;Why is my drone flipping (overturning) when I try to take off?&quot;">​</a></h2><p>Check the following:</p><ul><li><strong>Flight Controller Orientation</strong>: Does the tilt of the drone model in the Betaflight Configurator &quot;Setup&quot; tab match the tilt of the real drone? (The red arrow shows where the camera is located). If it doesn&#39;t match, you must adjust it on the &quot;Configuration&quot; tab in the &quot;Board and Sensor Alignment&quot; section.</li><li><strong>Motor Mapping</strong>: In the Betaflight &quot;Motors&quot; tab, the mixer should be &quot;Quad X&quot; (for quadcopters), and the motor order must match the numbering in the diagram.</li><li><strong>Motor Rotation</strong>: The &quot;Motors&quot; tab shows the rotation direction. By default, it&#39;s &quot;props-in&quot; (front props spin toward the camera). &quot;Props-out&quot; is also available by checking the &quot;Motor direction is reversed&quot; box. NOTE: This checkbox does not change the motor rotation; it only tells the firmware what direction to expect.</li><li><strong>Propeller Installation</strong>: Propellers must be installed according to the rotation scheme. The manufacturer&#39;s logo and size markings on the propeller should face upward.</li></ul><h2 id="why-doesn-t-the-drone-respond-to-throttle-and-spin-motors-in-pairs" tabindex="-1">Why doesn&#39;t the drone respond to throttle and spin motors in pairs? <a class="header-anchor" href="#why-doesn-t-the-drone-respond-to-throttle-and-spin-motors-in-pairs" aria-label="Permalink to &quot;Why doesn&#39;t the drone respond to throttle and spin motors in pairs?&quot;">​</a></h2><p>You have &quot;Turtle Mode&quot; activated (known as &quot;Flip Over After Crash&quot; in Betaflight &quot;Modes&quot;). It&#39;s used if your drone is stuck and needs a nudge to fly out, or if it&#39;s upside down on a flat surface and you need it to flip over to resume flight. Deactivate this option, arm the drone, and it should respond normally to the sticks if basic settings are correct and props are installed.</p><h2 id="how-do-i-bind-crossfire-elrs-frsky" tabindex="-1">How do I bind Crossfire / ELRS / FrSky? <a class="header-anchor" href="#how-do-i-bind-crossfire-elrs-frsky" aria-label="Permalink to &quot;How do I bind Crossfire / ELRS / FrSky?&quot;">​</a></h2><ul><li><a href="https://doggydog.blog/update/obnovlyaem-i-bindim-tbs-crossfire/" target="_blank" rel="noreferrer">Crossfire</a></li><li><a href="https://expresslrs.ru/Manuals/Binding/" target="_blank" rel="noreferrer">ELRS</a></li><li><a href="https://rcdetails.info/kak-privyazat-priemnik-k-apparature-upravleniya-frsky-taranis/" target="_blank" rel="noreferrer">FrSky</a></li></ul><h2 id="why-isn-t-anything-working-in-betaflight-4-4" tabindex="-1">Why isn&#39;t *anything* working in Betaflight 4.4? <a class="header-anchor" href="#why-isn-t-anything-working-in-betaflight-4-4" aria-label="Permalink to &quot;Why isn&#39;t \\*anything\\* working in Betaflight 4.4?&quot;">​</a></h2><ol><li><strong>Configurator Version</strong>: You must use the latest version of the Betaflight Configurator (currently 10.9 or newer, version is displayed at the top left). Old configurator versions may work incorrectly with new firmware versions (see <a href="https://propwashservice.com/en/community/software" target="_blank" rel="noreferrer">Software section</a>).</li><li><strong>Cloud Build System</strong>: Betaflight 4.4 uses a cloud build system. When flashing, you must specify the required radio protocol (CRSF for ELRS and Crossfire; for SPI receivers, the choice doesn&#39;t matter). Options like &quot;Magnetometer&quot; (if you have a compass) must be added in the options string where GPS, Led Strip, OSD, etc., are selected by default. Remove options you don&#39;t need, but if unsure, leave them. You can leave other lines as they are. If you check &quot;Core Only,&quot; the parameter fields will disappear and the full firmware will be loaded, BUT for F411 and F722 chips, GPS functionality will be missing due to size constraints. If you need GPS, use the cloud build system.</li><li><strong>Custom Defaults</strong>: After flashing, upon the first connection, a window appears asking to apply custom defaults. <strong>You must accept this</strong> for the flight controller configuration to load; otherwise, the firmware won&#39;t know about the sensors and ports on the FC.</li></ol><h2 id="i-calibrated-the-accelerometer-but-the-drone-model-is-still-rotated-incorrectly-what-do-i-do" tabindex="-1">I calibrated the accelerometer, but the drone model is still rotated incorrectly. What do I do? <a class="header-anchor" href="#i-calibrated-the-accelerometer-but-the-drone-model-is-still-rotated-incorrectly-what-do-i-do" aria-label="Permalink to &quot;I calibrated the accelerometer, but the drone model is still rotated incorrectly. What do I do?&quot;">​</a></h2><p>Flight controller rotation is handled in the &quot;Configuration&quot; tab. The &quot;Calibrate Accelerometer&quot; button only calibrates the horizontal position; it doesn&#39;t know the heading (yaw). You must set the rotation offset manually.</p><h2 id="battery-questions-charging-discharging-levels-charging-current-storage-how-long-can-they-stay-charged-what-is-the-second-connector-for" tabindex="-1">Battery questions: Charging/discharging levels? Charging current? Storage? How long can they stay charged? What is the second connector for? <a class="header-anchor" href="#battery-questions-charging-discharging-levels-charging-current-storage-how-long-can-they-stay-charged-what-is-the-second-connector-for" aria-label="Permalink to &quot;Battery questions: Charging/discharging levels? Charging current? Storage? How long can they stay charged? What is the second connector for?&quot;">​</a></h2><p><a href="https://propwashservice.com/en/intro/power" target="_blank" rel="noreferrer">Everything about batteries</a></p>',23)])])}const f=t(n,[["render",i]]);export{p as __pageData,f as default};
